import { type ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Container, SelectList, Text, Spacer } from "@mariozechner/pi-tui";
import { readdir, stat } from "node:fs/promises";
import { resolve, join } from "node:path";
import os from "node:os";

export default function (pi: ExtensionAPI) {
  pi.registerCommand("session-import", {
    description: "Browse and import past sessions",
    handler: async (_, ctx) => {
      const sessionDir = resolve(os.homedir(), ".pi/agent/sessions");

      // Recursively find all .jsonl files with mtime
      async function getFiles(dir: string): Promise<{ path: string; mtime: number }[]> {
        const entries = await readdir(dir, { withFileTypes: true });
        const results = await Promise.all(
          entries.map(async (res) => {
            const resPath = resolve(dir, res.name);
            if (res.isDirectory()) {
              return getFiles(resPath);
            } else if (res.name.endsWith(".jsonl")) {
              const stats = await stat(resPath);
              return [{ path: resPath, mtime: stats.mtimeMs }];
            }
            return [];
          })
        );
        return results.flat();
      }

      const fileEntries = await getFiles(sessionDir);
      fileEntries.sort((a, b) => b.mtime - a.mtime);

      if (fileEntries.length === 0) {
        ctx.ui.notify("No session files found.", "warning");
        return;
      }

      const items = fileEntries.map(entry => ({
        value: entry.path,
        label: entry.path.split('/').pop() || entry.path,
        description: entry.path.replace(os.homedir(), "~")
      }));

      const selectedPath = await ctx.ui.custom<string>((tui, theme, _kb, done) => {
        const container = new Container();
        container.addChild(new Text(theme.fg("accent", theme.bold(" Select Session to Import")), 1, 0));
        container.addChild(new Spacer(1));

        const list = new SelectList(items, 15, theme);

        list.onSelect = (item) => done(item.value);
        list.onCancel = () => done("");
        container.addChild(list);

        return {
          render: (w) => container.render(w),
          invalidate: () => container.invalidate(),
          handleInput: (data) => {
            list.handleInput(data);
            tui.requestRender();
          },
        };
      }, { overlay: true });

      if (selectedPath) {
        // We notify the user of the command to run. 
        // We can't automatically run /import from inside an extension, 
        // but we can provide the exact path which is now on their screen.
        ctx.ui.notify(`Run: /import ${selectedPath}`, "info");
        ctx.ui.setEditorText(`/import ${selectedPath}`);
      }
    },
  });
}

/**
 * Hello Tool - Minimal custom tool example
 */

import { Type } from "@earendil-works/pi-ai";
import { defineTool, type ExtensionAPI } from "@earendil-works/pi-coding-agent";

const helloTool = defineTool({
	name: "hello",
	label: "Hello",
	description: "A simple greeting tool",
	parameters: Type.Object({
		name: Type.String({ description: "Name to greet" }),
	}),

	async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
		return {
			content: [{ type: "text", text: `Hello, ${params.name}!` }],
			details: { greeted: params.name },
		};
	},
});

export default function (pi: ExtensionAPI) {
	pi.registerTool(helloTool);
}

/**
 * Commands Extension
 *
 * Demonstrates the pi.getCommands() API by providing a /commands command
 * that lists all available slash commands in the current session.
 *
 * Usage:
 * 1. Copy this file to ~/.pi/agent/extensions/ or your project's .pi/extensions/
 * 2. Use /commands to see available commands
 * 3. Use /commands extensions to filter by source
 */

import type { ExtensionAPI, SlashCommandInfo } from "@earendil-works/pi-coding-agent";

export default function commandsExtension(pi: ExtensionAPI) {
	pi.registerCommand("commands", {
		description: "List available slash commands",
		getArgumentCompletions: (prefix) => {
			const sources = ["extension", "prompt", "skill"];
			const filtered = sources.filter((s) => s.startsWith(prefix));
			return filtered.length > 0 ? filtered.map((s) => ({ value: s, label: s })) : null;
		},
		handler: async (args, ctx) => {
			const commands = pi.getCommands();
			const sourceFilter = args.trim() as "extension" | "prompt" | "skill" | "";

			// Filter by source if specified
			const filtered = sourceFilter ? commands.filter((c) => c.source === sourceFilter) : commands;

			if (filtered.length === 0) {
				ctx.ui.notify(sourceFilter ? `No ${sourceFilter} commands found` : "No commands found", "info");
				return;
			}

			// Build selection items grouped by source
			const formatCommand = (cmd: SlashCommandInfo): string => {
				const desc = cmd.description ? ` - ${cmd.description}` : "";
				return `/${cmd.name}${desc}`;
			};

			const items: string[] = [];
			const sources: Array<{ key: "extension" | "prompt" | "skill"; label: string }> = [
				{ key: "extension", label: "Extensions" },
				{ key: "prompt", label: "Prompts" },
				{ key: "skill", label: "Skills" },
			];

			for (const { key, label } of sources) {
				const cmds = filtered.filter((c) => c.source === key);
				if (cmds.length > 0) {
					items.push(`--- ${label} ---`);
					items.push(...cmds.map(formatCommand));
				}
			}

			// Show in a selector (user can scroll and see all commands)
			const selected = await ctx.ui.select("Available Commands", items);

			// If user selected a command (not a header), offer to show its path
			if (selected && !selected.startsWith("---")) {
				const cmdName = selected.split(" - ")[0].slice(1); // Remove leading /
				const cmd = commands.find((c) => c.name === cmdName);
				if (cmd?.sourceInfo.path) {
					const showPath = await ctx.ui.confirm(cmd.name, `View source path?\n${cmd.sourceInfo.path}`);
					if (showPath) {
						ctx.ui.notify(cmd.sourceInfo.path, "info");
					}
				}
			}
		},
	});
}

